import numpy as np
from collections import deque

def find_connected_components(grid, value):
    H, W = grid.shape
    visited = set()
    components = []
    for r in range(H):
        for c in range(W):
            if grid[r,c] == value and (r,c) not in visited:
                comp = set()
                queue = deque([(r,c)])
                comp.add((r,c))
                while queue:
                    cr, cc = queue.popleft()
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in comp and grid[nr,nc] == value:
                            comp.add((nr,nc))
                            queue.append((nr,nc))
                visited |= comp
                components.append(comp)
    return components

