import numpy as np
from collections import deque, Counter

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    output = grid.copy()

    # 1. Find background color (most frequent)
    counts = Counter(grid.flatten().tolist())
    bg_color = counts.most_common(1)[0][0]

    # 2. Find fill colors (appearing exactly once)
    fill_colors = [c for c, n in counts.items() if n == 1]

    # 3. For each fill color, do BFS to find active cells
    for fill_color in fill_colors:
        fill_pos = list(zip(*np.where(grid == fill_color)))
        if not fill_pos:
            continue
        fr, fc = fill_pos[0]

        # Find path color (non-bg 4-adjacent to fill)
        path_color = None
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = fr+dr, fc+dc
            if 0 <= nr < H and 0 <= nc < W and grid[nr,nc] != bg_color and grid[nr,nc] != fill_color:
                path_color = int(grid[nr,nc])
                break

        if path_color is None:
            continue

        # BFS from fill
        active = set()
        queue = deque()
        active.add((fr, fc))
        queue.append((fr, fc))

        while queue:
            r, c = queue.popleft()
            cell_color = int(grid[r,c])
            is_path_or_fill = (cell_color == path_color or cell_color == fill_color)

            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0:
                        continue
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < H and 0 <= nc < W and (nr, nc) not in active:
                        ncol = int(grid[nr, nc])
                        if ncol == bg_color:
                            continue
                        if is_path_or_fill:
                            # From path/fill: expand to all non-bg
                            active.add((nr, nc))
                            queue.append((nr, nc))
                        else:
                            # From shape outline: expand only to path cells
                            if ncol == path_color:
                                active.add((nr, nc))
                                queue.append((nr, nc))

        # 4. Find enclosed bg-regions
        # Flood fill from boundary bg-cells
        boundary_bg = set()
        queue2 = deque()
        for r in range(H):
            for c in range(W):
                if (r == 0 or r == H-1 or c == 0 or c == W-1) and grid[r,c] == bg_color:
                    if (r,c) not in boundary_bg:
                        boundary_bg.add((r,c))
                        queue2.append((r,c))

        while queue2:
            r, c = queue2.popleft()
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in boundary_bg and grid[nr,nc] == bg_color:
                    boundary_bg.add((nr,nc))
                    queue2.append((nr,nc))

        # Enclosed bg-cells = bg-cells NOT in boundary_bg
        enclosed = set()
        for r in range(H):
            for c in range(W):
                if grid[r,c] == bg_color and (r,c) not in boundary_bg:
                    enclosed.add((r,c))

        # 5. For each enclosed bg-region, check if any 4-adj non-bg cell is active
        # Find connected components of enclosed cells
        visited_enc = set()
        for r, c in enclosed:
            if (r,c) in visited_enc:
                continue
            # BFS to find this region
            region = set()
            q = deque([(r,c)])
            region.add((r,c))
            while q:
                cr, cc = q.popleft()
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = cr+dr, cc+dc
                    if (nr,nc) in enclosed and (nr,nc) not in region:
                        region.add((nr,nc))
                        q.append((nr,nc))
            visited_enc |= region

            # Check if any 4-adj non-bg cell is active
            should_fill = False
            for cr, cc in region:
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = cr+dr, cc+dc
                    if 0 <= nr < H and 0 <= nc < W and (nr,nc) in active:
                        should_fill = True
                        break
                if should_fill:
                    break

            if should_fill:
                for cr, cc in region:
                    output[cr, cc] = fill_color

