    for r in range(H):
        for c in range(W):
            if (r == 0 or r == H-1 or c == 0 or c == W-1) and grid[r,c] == bg_color:
                if (r,c) not in exterior:
                    exterior.add((r,c))
                    queue.append((r,c))
    while queue:
        r, c = queue.popleft()
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in exterior and grid[nr,nc] == bg_color:
                exterior.add((nr,nc))
                queue.append((nr,nc))

    # Find connected components within exterior to separate true exterior from edge interiors
    ext_visited = set()
    ext_components = []
    for cell in exterior:
        if cell in ext_visited:
            continue
        comp = set()
        q = deque([cell])
        comp.add(cell)
        while q:
            r, c = q.popleft()
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if (nr,nc) in exterior and (nr,nc) not in comp:
                    comp.add((nr,nc))
                    q.append((nr,nc))
        ext_visited |= comp
        ext_components.append(comp)

