                        if is_path_or_fill:
                            # From path/fill: expand to all non-bg
                            active.add((nr, nc))
                            queue.append((nr, nc))
                        else:
                            # From shape outline: expand only to path cells
                            if ncol == path_color:
                                active.add((nr, nc))
                                queue.append((nr, nc))

        # 4. Find enclosed bg-regions
        # Flood fill from boundary bg-cells
        boundary_bg = set()
        queue2 = deque()
        for r in range(H):
            for c in range(W):
                if (r == 0 or r == H-1 or c == 0 or c == W-1) and grid[r,c] == bg_color:
