        # Find connected components of enclosed cells
        visited_enc = set()
        for r, c in enclosed:
            if (r,c) in visited_enc:
                continue
            # BFS to find this region
            region = set()
            q = deque([(r,c)])
            region.add((r,c))
            while q:
                cr, cc = q.popleft()
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = cr+dr, cc+dc
                    if (nr,nc) in enclosed and (nr,nc) not in region:
                        region.add((nr,nc))
                        q.append((nr,nc))
