import numpy as np
from collections import deque, Counter

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    output = grid.copy()

    counts = Counter(grid.flatten().tolist())
    bg_color = counts.most_common(1)[0][0]
    fill_colors = [c for c, n in counts.items() if n == 1]

    # Find ALL bg-regions (4-connected)
    bg_visited = set()
    all_bg_regions = []
    for r in range(H):
        for c in range(W):
            if grid[r,c] == bg_color and (r,c) not in bg_visited:
                region = set()
                q = deque([(r,c)])
                region.add((r,c))
                while q:
                    cr, cc = q.popleft()
                    for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                        nr, nc = cr+dr, cc+dc
                        if 0 <= nr < H and 0 <= nc < W and grid[nr,nc] == bg_color and (nr,nc) not in region:
                            region.add((nr,nc))
                            q.append((nr,nc))
                bg_visited |= region
                all_bg_regions.append(region)

    if not all_bg_regions:
        return output.tolist()
    largest_idx = max(range(len(all_bg_regions)), key=lambda i: len(all_bg_regions[i]))

    candidate_regions = []
    region_borders = []
    for i, region in enumerate(all_bg_regions):
        if i != largest_idx and len(region) <= 50:
            border = set()
            for r, c in region:
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < H and 0 <= nc < W and grid[nr,nc] != bg_color:
                        border.add((nr,nc))
            candidate_regions.append(region)
            region_borders.append(border)

    for fill_color in fill_colors:
        fill_pos = list(zip(*np.where(grid == fill_color)))
        if not fill_pos:
            continue
        fr, fc = fill_pos[0]

        path_color = None
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = fr+dr, fc+dc
            if 0 <= nr < H and 0 <= nc < W and grid[nr,nc] != bg_color and grid[nr,nc] != fill_color:
                path_color = int(grid[nr,nc])
                break
        if path_color is None:
            continue

        all_path_cells = set(zip(*np.where(grid == path_color)))

        # BFS: 8-connected path cells, PLUS allow bridging through non-bg intermediary
        active_path = set()
        q = deque()
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                if dr == 0 and dc == 0: continue
                nr, nc = fr+dr, fc+dc
                if (nr,nc) in all_path_cells and (nr,nc) not in active_path:
                    active_path.add((nr,nc))
                    q.append((nr,nc))

        while q:
            r, c = q.popleft()
            # Direct 8-connected path cells
            for dr in [-1,0,1]:
                for dc in [-1,0,1]:
                    if dr == 0 and dc == 0: continue
                    nr, nc = r+dr, c+dc
                    if (nr,nc) in all_path_cells and (nr,nc) not in active_path:
                        active_path.add((nr,nc))
                        q.append((nr,nc))
            # Bridge: step through one non-bg, non-path-color cell to reach another path cell
            for dr in [-1,0,1]:
                for dc in [-1,0,1]:
                    if dr == 0 and dc == 0: continue
                    mr, mc = r+dr, c+dc  # intermediate
                    if 0 <= mr < H and 0 <= mc < W and grid[mr,mc] != bg_color and grid[mr,mc] != path_color:
                        # Check if any 8-neighbor of intermediate is a path cell
                        for dr2 in [-1,0,1]:
                            for dc2 in [-1,0,1]:
                                if dr2 == 0 and dc2 == 0: continue
                                nr, nc = mr+dr2, mc+dc2
                                if (nr,nc) in all_path_cells and (nr,nc) not in active_path:
                                    active_path.add((nr,nc))
                                    q.append((nr,nc))

        # Filter candidates and iteratively find shapes
        valid_candidates = []
        valid_borders = []
        for region, border in zip(candidate_regions, region_borders):
            has_path_in_border = any(int(grid[r,c]) == path_color for r,c in border)
            if not has_path_in_border:
                valid_candidates.append(region)
                valid_borders.append(border)

        filled_shapes = set()
        changed = True
        while changed:
            changed = False
            for i, (region, border) in enumerate(zip(valid_candidates, valid_borders)):
                if i in filled_shapes:
                    continue
                shape_reached = False
                for br, bc in border:
                    if shape_reached: break
                    for dr in [-1,0,1]:
                        for dc in [-1,0,1]:
                            if (br+dr, bc+dc) in active_path:
                                shape_reached = True
                                break
                if shape_reached:
                    filled_shapes.add(i)
                    changed = True
                    for br, bc in border:
                        for dr in [-1,0,1]:
                            for dc in [-1,0,1]:
                                if dr == 0 and dc == 0: continue
                                nr, nc = br+dr, bc+dc
                                if (nr,nc) in all_path_cells and (nr,nc) not in active_path:
                                    active_path.add((nr,nc))
                                    pq = deque([(nr,nc)])
                                    while pq:
                                        pr, pc = pq.popleft()
                                        for ddr in [-1,0,1]:
                                            for ddc in [-1,0,1]:
                                                if ddr == 0 and ddc == 0: continue
                                                nnr, nnc = pr+ddr, pc+ddc
                                                if (nnr,nnc) in all_path_cells and (nnr,nnc) not in active_path:
                                                    active_path.add((nnr,nnc))
                                                    pq.append((nnr,nnc))
                                        # Also bridge
                                        for ddr in [-1,0,1]:
                                            for ddc in [-1,0,1]:
                                                if ddr == 0 and ddc == 0: continue
                                                mr, mc = pr+ddr, pc+ddc
                                                if 0<=mr<H and 0<=mc<W and grid[mr,mc]!=bg_color and grid[mr,mc]!=path_color:
                                                    for ddr2 in [-1,0,1]:
                                                        for ddc2 in [-1,0,1]:
                                                            if ddr2==0 and ddc2==0: continue
                                                            nnr,nnc = mr+ddr2,mc+ddc2
                                                            if (nnr,nnc) in all_path_cells and (nnr,nnc) not in active_path:
                                                                active_path.add((nnr,nnc))
                                                                pq.append((nnr,nnc))

        for i in filled_shapes:
            for r, c in valid_candidates[i]:
                output[r, c] = fill_color

    return output.tolist()

